Let's build something more realistic. Create a Go web server and containerize it. Create main.go: package main import ( "encoding/json" "fmt" "net/http" "os" "runtime"
) type Response struct { Message string `json:"message"` Hostname string `json:"hostname"` GoVer string `json:"go_version"` Path string `json:"path"`
} func handler(w http.ResponseWriter, r *http.Request) { hostname, _ := os.Hostname() resp := Response{ Message: "Hello from Nix-built container!", Hostname: hostname, GoVer: runtime.Version(), Path: r.URL.Path, } w.Header().Set("Content-Type", "application/json") json.NewEncoder(w).Encode(resp)
} func main() { http.HandleFunc("/", handler) fmt.Println("Server running on :8080") http.ListenAndServe(":8080", nil)
} Create nix/go-package.nix: _: { config.perSystem = { pkgs, ... }: { packages.go-server = pkgs.buildGoModule { pname = "my-go-server"; version = "0.1.0"; src = ../.; vendorHash = null; # No external dependencies CGO_ENABLED = 0; # Static binary }; };
} Create nix/go-container.nix: _: { config.perSystem = { pkgs, config, ... }: { packages.go-container = pkgs.dockerTools.buildLayeredImage { name = "my-go-server"; tag = "latest"; contents = [ config.packages.go-server ]; config = { Cmd = [ "/bin/my-go-server" ]; ExposedPorts = { "8080/tcp" = {}; }; }; maxLayers = 125; }; };
} Build and run: git add main.go nix/go-package.nix nix/go-container.nix
nix build '.#go-container'
docker load < result # Stop any previous run, then start fresh
docker rm -f my-go-server 2>/dev/null || true
docker run --rm --name my-go-server -p 8080:8080 my-go-server:latest In another terminal: curl http://localhost:8080/ To stop the container , press Ctrl+C. The --rm flag auto-cleans it. If port 8080 is busy, the docker rm -f line above handles leftover containers from previous runs. Check the final image size: docker images my-go-server A statically compiled Go binary in a Nix container typically results in an image under 15 MB .

